import React, { useEffect } from 'react';
import clsx from 'clsx';
import { makeStyles, useTheme } from '@material-ui/core/styles';
import Input from '@material-ui/core/Input';
import InputLabel from '@material-ui/core/InputLabel';
import MenuItem from '@material-ui/core/MenuItem';
import FormControl from '@material-ui/core/FormControl';
import ListItemText from '@material-ui/core/ListItemText';
import Select from '@material-ui/core/Select';
import Checkbox from '@material-ui/core/Checkbox';
import Chip from '@material-ui/core/Chip';

const useStyles = makeStyles((theme) => ({
  formControl: {
    minWidth: '100%',
    maxWidth: '100%',
  },
  chips: {
    display: 'flex',
    flexWrap: 'wrap',
  },
  chip: {
    margin: 2,
  },
  noLabel: {
    marginTop: theme.spacing(3),
  },
}));

const ITEM_HEIGHT = 48;
const ITEM_PADDING_TOP = 8;
const MenuProps = {
  PaperProps: {
    style: {
      maxHeight: ITEM_HEIGHT * 4.5 + ITEM_PADDING_TOP,
      width: 250,
    },
  },
};



function getStyles(name, personName, theme) {
  return {
    fontWeight:
      personName.indexOf(name) === -1
        ? theme.typography.fontWeightRegular
        : theme.typography.fontWeightMedium,
  };
}

export default function MultipleSelect(props) {
  const classes = useStyles();
  const theme = useTheme();
  const [personName, setPersonName] = React.useState([]);
  var workflows= [
    {
    approvalException: "false",
    approvalExpirey: "5",
    comments: "COMMENST",
    companyId: "5f58e057ad85261cd05a19cf",
    companyName: "COMPANYONE",
    created: "2020-10-20T09:37:31.359Z",
    createdBy: "waqas",
    marDeletion: "",
    organizationId: "5f58e04cad85261cd05a19ce",
    organizationName: "ORGONE",
    referenceTicket: "7878",
    reviewException: "false",
    reviewExpirey: "5",
    titleApprover: "PROJECT MANAGER",
    titleApproverId: "5f9beaecd1b97d3b14b17032",
    titleReviewer: "DEVELOPER",
    titleReviewerId: "5f58e071ad85261cd05a19d2",
    workflowName: "FLOW 1",
  },
  {
    approvalException: "false",
    approvalExpirey: "5",
    comments: "COMMENST",
    companyId: "5f58e057ad85261cd05a19cf",
    companyName: "COMPANYONE",
    created: "2020-10-20T09:37:31.359Z",
    createdBy: "waqas",
    marDeletion: "",
    organizationId: "5f58e04cad85261cd05a19ce",
    organizationName: "ORGONE",
    referenceTicket: "7878",
    reviewException: "false",
    reviewExpirey: "5",
    titleApprover: "PROJECT MANAGER",
    titleApproverId: "5f9beaecd1b97d3b14b17032",
    titleReviewer: "DEVELOPER",
    titleReviewerId: "5f58e071ad85261cd05a19d2",
    workflowName: "FLOW 2",
  }
];
  const handleChange = (event) => {
    setPersonName(event.target.value);
    props.onChange(event.target.value);
  };
  const handleChangeMultiple = (event) => {
    const { options } = event.target;
    const value = [];
    for (let i = 0, l = options.length; i < l; i += 1) {
      if (options[i].selected) {
        value.push(options[i].value);
      }
    }
    setPersonName(value);
  };
  useEffect(()=>{
    console.log(props.existingWorkflows);
    props.existingWorkflows ?
      setPersonName(props.existingWorkflows):  
      setPersonName([]);
  },[props.workFlows])

  return (
    <div>
      <FormControl className={classes.formControl}>
        <InputLabel id="demo-mutiple-chip-label">WORKFLOWS</InputLabel>
        <Select
          labelId="demo-mutiple-chip-label"
          id="demo-mutiple-chip"
          multiple
          value={personName}
          disabled={props.isDisable}
          onChange={handleChange}
          input={<Input id="select-multiple-chip" />}
          renderValue={(selected) => (
            <div className={classes.chips}>
              {selected.map((value) => (
                <Chip key={value} label={value} className={classes.chip} />
              ))}
            </div>
          )}
          MenuProps={MenuProps}
        >
          {props.workFlows.map((name, index) => (
            <MenuItem key={index} value={name.workflowName} style={getStyles(name, personName, theme)}>
              {name.workflowName}
            </MenuItem>
          )) }
        </Select>
      </FormControl>
    </div>
  );
}
