/*eslint-disable*/
import React, { useState, useEffect } from "react";
// @material-ui/core components
import { TextField, makeStyles, CircularProgress, Slide, Dialog } from "@material-ui/core";
import SweetAlert from "react-bootstrap-sweetalert";
import { useDispatch } from "react-redux";
import { getTeam } from "actions";
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import axios from "axios";
import { Animated } from "react-animated-css";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";
import OtpCheck from "../Authorization/OtpCheck";
import MultipleSelect from "./MultiSelect";
var Token = localStorage.getItem("cooljwt");
const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

const Transition = React.forwardRef(function Transition(props, ref) {
  return <Slide direction="down" ref={ref} {...props} />;
});

export default function ViewTeam(props) {
  // register form
  const dispatch = useDispatch();
  const [animateTable, setAnimateTable] = React.useState(true);
  const [otpModal, setotpModal] = React.useState(false);
  const [loading, setLoading] = React.useState(false);
  const [OTP, setOTP] = React.useState("");
  const [formState, setFormState] = useState({
    orgs: [],
    comp: [],
    depts: [],
    selectedWorkFlows:[],
    workFlows:[],
    isRegistering: false,
    values: {
      teamName: props.teamDetail.teamName,
      referenceTicket: props.teamDetail.referenceTicket,
      titleHead: props.teamDetail.titleHead,
      organizationName: props.teamDetail.organizationName,
      companyName: props.teamDetail.companyName,
      departmentName: props.teamDetail.departmentName,
      workflows:props.teamDetail.workFlows
    },
    errors: {
      teamName: "",
      referenceTicket: "",
      titleHead: "",
      organizationName: "",
      companyName: "",
      departmentName: "",
    },
  });
  const setWorkFlows = (x) => {
    setFormState((formState) => ({
      ...formState,
      selectedWorkFlows: x
    }));
  }
  const getWorkFlows = (org) => {
    return new Promise((res, rej)=>{
      axios({
        method: "get",
        url: `${process.env.REACT_APP_LDOCS_API_WORKFLOW_URL}/workflow/getworkflowbyorganization/${org}`,
        headers: { cooljwt: Token },
      })
        .then((response) => {
          setFormState((formState) => ({
            ...formState,
            workFlows: response.data,
          }));
        })
    })     
  }

  const getCompanies = () => {
    axios
      .get(`${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/comlistwoi`)
      .then((response) => {
        setFormState((formState) => ({
          ...formState,
          comp: response.data,
        }));
      })
      .catch((error) => {
        console.log("Unable to get Departments please contact at contact@avantas.io")
      });
  };
  const getOrganizations = () => {
    axios
      .get(`${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/orglistwoi`)
      .then((response) => {
        setFormState((formState) => ({
          ...formState,
          orgs: response.data,
        }));
      })
      .catch((error) => {
        console.log("Unable to get Departments please contact at contact@avantas.io")
      });
    };
    const getDepartments = () => {
      axios
        .get(`${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/deplist`)
        .then((response) => {
          setFormState((formState) => ({
            ...formState,
            depts: response.data,
          }));
          setLoading(false);
        })
        .catch((error) => {
          console.log("Unable to get Departments please contact at contact@avantas.io")
          setLoading(false);
        });
    };
  useEffect(() => {
    if(props.Updating){
      setLoading(true);
      getCompanies();
      getOrganizations();
      getDepartments();
      getWorkFlows(props.teamDetail.organizationName);
    }
  }, []);
  const handleChange = (event) => {
  event.persist();
  if (event.target.name == "organizationName") {
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        companyName: "",
        departmentName: ""
      },
    }));
  } else if (event.target.name == "companyName") {
      setFormState((formState) => ({
        ...formState,
        values: {
          ...formState.values,
          departmentName: "",
        },
      }));
        }
  setFormState((formState) => ({
    ...formState,
    values: {
      ...formState.values,
      [event.target.name]: event.target.value.toUpperCase(),
    },
  }));
  };

const sweetClass = sweetAlertStyle();
const [alert, setAlert] = React.useState(null);
const successAlert = (msg) => {
  setAlert(
    <SweetAlert
      success
      style={{ display: "block", marginTop: "-100px" }}
      title="Success!"
      onConfirm={() => hideAlert()}
      onCancel={() => hideAlert()}
      confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
    >
      {msg}
    </SweetAlert>
  );
};
const errorAlert = (msg) => {
  setAlert(
    <SweetAlert
      error
      style={{ display: "block", marginTop: "-100px" }}
      title="Error!"
      onConfirm={() => hideErrorAlert()}
      onCancel={() => hideErrorAlert()}
      confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
    >
      {msg ? msg : "Unable To Register Team Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}"}
    </SweetAlert>
  );
};
const hideAlert = () => {
closeModal();
setAlert(null);
};
const hideErrorAlert = () => {
setAlert(null);
};
const handleUpdate = () => {

  let teamName;
  let referenceTicket;
  let titleHead;
  let organizationName;
  let companyName;
  let departmentName;
  const Check = require("is-null-empty-or-undefined").Check;
  var error = false;

  if (!Check(formState.values.teamName)) {
    teamName = "success";
  } else {
    teamName = "error";
    error = true;
  }
  if (!Check(formState.values.departmentName)) {
    departmentName = "success";
  } else {
    departmentName = "error";
    error = true;
  }
  if (!Check(formState.values.referenceTicket)) {
    referenceTicket = "success";
  } else {
    referenceTicket = "error";
    error = true;
  }
  if (!Check(formState.values.titleHead)) {
    titleHead = "success";
  } else {
    titleHead = "error";
    error = true;
  }
  if (!Check(formState.values.organizationName)) {
    organizationName = "success";
  } else {
    organizationName = "error";
    error = true;
  }
  if (!Check(formState.values.companyName)) {
    companyName = "success";
  } else {
    companyName = "error";
    error = true;
  }
  setFormState((formState) => ({
    ...formState,
    errors: {
      ...formState.errors,
      teamName:teamName,
      departmentName: departmentName,
      referenceTicket: referenceTicket,
      titleHead: titleHead,
      organizationName: organizationName,
      companyName: companyName,
    },
  }));
  if (error) {
    setFormState((formState) => ({
      ...formState,
      isRegistering: false
    }));
    errorAlert("Invalid Details!");
    return false;
  } else {
    if(!OTP){
      setotpModal(true);
      return false;
    }
    setFormState((formState) => ({
      ...formState,
      isRegistering: true,
    }));
    let data = {
      teamName: formState.values.teamName,
      organizationName: formState.values.organizationName,
      companyName: formState.values.companyName,
      departmentName: formState.values.departmentName,
      titleHead: formState.values.titleHead,
      referenceTicket: formState.values.referenceTicket,
      otp: OTP,
      workFlows:formState.selectedWorkFlows
    };
    let msg = "";
    axios({
      method: "patch",
      url: `${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/updtea`,
      headers: { "cooljwt": Token },
      data: data,
    })
      .then((response) => {
        dispatch(getTeam());
        setOTP("");
        props.getTeams();
        setFormState((formState) => ({
          ...formState,
          isRegistering: false,
        }));
        msg = "Team Updated Successfully!";
        successAlert(msg);
      })
      .catch((error) => {
        setFormState((formState) => ({
          ...formState,
          isRegistering: false,
        }));
        msg =
          typeof error.response != "undefined"
            ? error.response.data
            : error.message;
        errorAlert(msg);
      });
  }
};
  const closeModal = () => {
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        teamName: "",
        referenceTicket: "",
        titleHead: "",
        organizationName: "",
        companyName: "",
        departmentName: "",
      },
      errors: {
        ...formState.errors,
        teamName: "",
        referenceTicket: "",
        titleHead: "",
        organizationName: "",
        companyName: "",
        departmentName: "",
      },
    }));
    props.closeModal();
  };
  useEffect(() => {
    if (!otpModal) {
      const Check = require("is-null-empty-or-undefined").Check;
      if (!Check(OTP)) {
        handleUpdate();
      }
    }
  }, [otpModal])
  const setOtpValue = (value) => {
    setOTP(value);
    setotpModal(false);  
  }
  const classes = useStyles();
  return (
    <Animated
      animationIn="bounceInRight"
      animationOut="bounceOutLeft"
      animationInDuration={1000}
      animationOutDuration={1000}
      isVisible={animateTable}
    >
      {alert}
      {otpModal ?
        <Dialog
            classes={{
              root: classes.center + " " + classes.modalRoot,
              paper: classes.modal,
            }}
            fullWidth={true}
            maxWidth={"xs"}
            open={otpModal}
            TransitionComponent={Transition}
            keepMounted
            onClose={() => setotpModal(false)}
            aria-labelledby="classic-modal-slide-title"
            aria-describedby="classic-modal-slide-description"
          >
               <OtpCheck setOtpValue={setOtpValue} /> 
          </Dialog>
        : ""}
      <GridContainer>
        <GridItem xs={12} sm={12} md={12}>
          <Card>
            <CardHeader color="info" icon>
              <CardIcon color="info">
                <h4 className={classes.cardTitle}>Team Details</h4>
              </CardIcon>
            </CardHeader>
            <CardBody>
              <GridContainer>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{
                    marginTop: "10px",
                    marginBottom: "10px",
                  }}
                >
                  <TextField
                    fullWidth={true}
                    label="Organization Name"
                    id="organizationName"
                    name="organizationName"
                    type="text"
                    disabled={true}
                    value={formState.values.organizationName || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{
                    marginTop: "10px",
                    marginBottom: "10px",
                  }}
                >
                  <TextField
                    fullWidth={true}
                    label="Company Name"
                    id="companyName"
                    name="companyName"
                    type="text"
                    disabled={true}
                    value={formState.values.companyName || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{
                    marginTop: "10px",
                    marginBottom: "10px",
                  }}
                >
                  <TextField
                    fullWidth={true}
                    label="Department Name"
                    id="departmentName"
                    name="departmentName"
                    type="text"
                    disabled={true}
                    value={formState.values.departmentName || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{
                    marginTop: "10px",
                    marginBottom: "10px",
                  }}
                >
                  <TextField
                    fullWidth={true}
                    label="Team Name"
                    id="teamName"
                    name="teamName"
                    type="text"
                    disabled={true}
                    value={formState.values.teamName || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{
                    marginTop: "10px",
                    marginBottom: "10px",
                  }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.titleHead === "error"}
                    helperText={
                      formState.errors.titleHead === "error"
                        ? "Valid Title Head is required"
                        : null
                    }
                    label="Title"
                    id="titleHead"
                    name="titleHead"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    type="text"
                    disabled={props.Updating ? false : true}
                    value={formState.values.titleHead || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{
                    marginTop: "10px",
                    marginBottom: "10px",
                  }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.referenceTicket === "error"}
                    helperText={
                      formState.errors.referenceTicket === "error"
                        ? "Valid Reference Ticket is required"
                        : null
                    }
                    label="Reference Ticket"
                    id="referenceTicket"
                    name="referenceTicket"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    type="text"
                    disabled={props.Updating ? false : true}
                    value={formState.values.referenceTicket || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={12}
                  lg={12}
                  style={{
                    marginTop: "10px",
                    marginBottom: "10px",
                  }}
                >
                <MultipleSelect existingWorkflows={formState.values.workflows} workFlows={props.Updating?formState.workFlows:[]} isDisable={props.Updating?false:true}  onChange={setWorkFlows} />
                </GridItem>
              </GridContainer>
              {props.Updating ?
                <>
                <Button
                color="info"
                className={classes.registerButton}
                disabled={formState.isRegistering}
                round
                type="button"
                onClick={handleUpdate}
                >
                  Update
                </Button>
                {formState.isRegistering ? 
                  <CircularProgress disableShrink />
                 : "" } 
                  </>
                  : "" }
                  {loading ? <CircularProgress disableShrink /> : ""}
              <Button
                color="danger"
                className={classes.registerButton}
                onClick={closeModal}
                round
              >
                Close
              </Button>
            </CardBody>
          </Card>
        </GridItem>
      </GridContainer>
    </Animated>
  );
}
