import React, { useState } from 'react';
import { makeStyles, Slide, MenuItem, TextField, CircularProgress } from '@material-ui/core';
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import axios from "axios";

const Transition = React.forwardRef(function Transition(props, ref) {
  return <Slide direction="down" ref={ref} {...props} />;
});
const useStyles = makeStyles((theme) => ({

  root: {
    height: "100%",
    flexGrow: 1,
    maxWidth: "100%",
  },
  root2: {
    display: 'flex',
    flexWrap: 'wrap',
    justifyContent: 'space-around',
    overflow: 'hidden',
    backgroundColor: theme.palette.background.paper,
  },
  gridList: {
    width: "100%",
    height: "100%",
  },
  icon: {
    color: 'rgba(255, 255, 255, 0.54)',
  },
  icons: {
    marginRight: theme.spacing(0.5),
    width: 20,
    height: 20,
  },
  link: {
    display: 'flex',
  },
}));
var Token = localStorage.getItem("cooljwt");

export default function Drawer(props) {
  const classes = useStyles();
  const [formState, setFormState] = useState({
    isRegistering: false,
    message: "",
    values: {
      cname: "",
      dname: ""
    },
    errors: {
      cname: "",
      dname: ""
    },
  });
  const handleChange = (event) => {
    event.persist();

    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        [event.target.name]: event.target.value,
      },
    }));
  };
  const handleSubmit = (e) => {
    e.preventDefault();
    setFormState((formState) => ({
      ...formState,
      isRegistering: true,
    }));
    let cname;
    let dname;
    const Check = require("is-null-empty-or-undefined").Check;
    var error = false;

    if (!Check(formState.values.cname)) {
      cname = "success";
    } else {
      cname = "error";
      error = true;
    }
    if (!Check(formState.values.dname)) {
      dname = "success";
    } else {
      dname = "error";
      error = true;
    }
    setFormState((formState) => ({
      ...formState,
      errors: {
        ...formState.errors,
        cname: cname,
        dname: dname
      },
    }));
    if (error) {
      setFormState((formState) => ({
        ...formState,
        isRegistering: false,
      }));
      return false;
    } else {
      var isPersonal;
      if(formState.values.cname == 'PERSONAL'){
          isPersonal = true; 
      }else{
          isPersonal = false;  
      }
      console.log(isPersonal);
         
      let data = {
        cname: formState.values.cname,
        dname: formState.values.dname,
        ispersonal: isPersonal
      }
      let msg = "";
      let method = "";
      if(props.action === "ADD"){
        method = "post";
      }else{
        method = "delete";
      }
      axios({
        method: method,
        url: `${process.env.REACT_APP_LDOCS_API_FILE_URL}/api/drawer`,
        data: data,
        headers: { "cooljwt": Token },
      })
        .then((response) => {
          props.getCabinats();
          setFormState((formState) => ({
            ...formState,
            isRegistering: false,
          }));
          msg = `Drawer ${props.action === "ADD" ? "Created" : "Deleted" } Successfully!`;
          props.notify(msg);
          closeModal();
        })
        .catch((error) => {
          setFormState((formState) => ({
            ...formState,
            isRegistering: false,
          }));
          msg =
            typeof error.response != "undefined"
              ? error.response.data
              : error.message;
          props.notify(msg);
        });
    }
  };
  const closeModal = () => {
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        cname: "",
        dname: ""
      },
      errors: {
        ...formState.errors,
        cname: "",
        dname: ""
      },
    }));
    props.closeModal();
  };
  return (
    <>
    <form onSubmit={handleSubmit}>
    <GridContainer style={{ marginTop: "10px", marginBottom: "20px" }}>
     {props.action === "ADD" ?  
     <>
     <GridItem
    xs={12}
    sm={12}
    md={12}
    lg={12}
  >
    <TextField
      className={classes.textField}
      error={formState.errors.cname === "error"}
      fullWidth={true}
      helperText={
        formState.errors.cname === "error"
          ? "Cabinat Name is required"
          : null
      }
      label="Cabinat Name"
      name="cname"
      onChange={(event) => {
        handleChange(event);
      }}
      select
      value={formState.values.cname || ""}
    >
      <MenuItem
        disabled
        classes={{
          root: classes.selectMenuItem,
        }}
      >
        Choose Cabinat
      </MenuItem>
      {props.Cabinats.map((cab, index) => {
        return (
          <MenuItem
            key={index}
            value={cab.name}
          >
            {cab.name}
          </MenuItem>
        );
      })}
    </TextField>
  </GridItem>
    <GridItem
      xs={12}
      sm={12}
      md={12}
      lg={12}
      style={{ marginTop: "10px", marginBottom: "10px" }}
    >
      <TextField
        fullWidth={true}
        error={formState.errors.dname === "error"}
        helperText={
          formState.errors.dname === "error"
            ? "Drawer Name is required"
            : null
        }
        label="Drawer Name"
        id="dname"
        name="dname"
        onChange={(event) => {
          handleChange(event);
        }}
        type="text"
        value={formState.values.dname || ""}
      />
    </GridItem>
    </>
    :
    <>
    <GridItem
    xs={12}
    sm={12}
    md={12}
    lg={12}
  >
    <TextField
      className={classes.textField}
      error={formState.errors.cname === "error"}
      fullWidth={true}
      helperText={
        formState.errors.cname === "error"
          ? "Cabinat Name is required"
          : null
      }
      label="Cabinat Name"
      name="cname"
      onChange={(event) => {
        handleChange(event);
      }}
      select
      value={formState.values.cname || ""}
    >
      <MenuItem
        disabled
        classes={{
          root: classes.selectMenuItem,
        }}
      >
        Choose Cabinat
      </MenuItem>
      {props.Cabinats.map((cab, index) => {
        return (
          <MenuItem
            key={index}
            value={cab.name}
          >
            {cab.name}
          </MenuItem>
        );
      })}
    </TextField>
  </GridItem>
  <GridItem
    xs={12}
    sm={12}
    md={12}
    lg={12}
  >
    <TextField
      className={classes.textField}
      error={formState.errors.dname === "error"}
      fullWidth={true}
      helperText={
        formState.errors.dname === "error"
          ? "Drawer Name is required"
          : null
      }
      label="Drawer Name"
      name="dname"
      onChange={(event) => {
        handleChange(event);
      }}
      select
      value={formState.values.dname || ""}
    >
      <MenuItem
        disabled
        classes={{
          root: classes.selectMenuItem,
        }}
      >
        Choose Drawer
      </MenuItem>
      {props.Cabinats.map((cab, index) => {
        return  cab.children.map((draw,index)=>{
            return (
                formState.values.cname === cab.name ?
            <MenuItem
                key={index}
                value={draw.name}
            >
                {draw.name}
            </MenuItem>
            :""
            );
        })
      })}
    </TextField>
  </GridItem>
  </>}
    </GridContainer>
    <Button
      color="info"
      className={classes.registerButton}
      round
      type="submit"
      style={{ float: "right" }}
    >
      {props.action === "ADD" ? "Create" : "Delete"}
    </Button>
    {formState.isRegistering ? (
      <CircularProgress disableShrink />
    ) : (
      ""
    )}
    <Button
      color="danger"
      type="button"
      className={classes.registerButton}
      onClick={closeModal}
      round
      style={{ float: "right" }}
    >
      Close
    </Button>
    </form>
    </>
  );
}