/*eslint-disable*/
import React, { useState, useEffect } from "react";
// @material-ui/core components
import {
  MenuItem,
  makeStyles,
  CircularProgress,
  TextField,
  Input,
  InputAdornment,
} from "@material-ui/core";
// core components
import MessageIcon from "@material-ui/icons/Message";

import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import jwt from "jsonwebtoken";
import CryptoJS from "crypto-js";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";

const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

export default function UploadFile(props) {
  // register form

  const [formState, setFormState] = useState({
    isRegistering: false,
    values: {
      cabinate:null,
      drawer:null,
      fileUpload: null,
      fileInitComments: "",
    },
    errors: {
      cabinate: "",
      drawer:null,
      fileUpload: "",
      fileInitComments: "",
    },
  });
  const [drawers, setDrawers] = useState([]);
      const classes = useStyles();
      const sweetClass = sweetAlertStyle();
      const [alert, setAlert] = React.useState(null);
      const successAlert = (msg) => {
        setAlert(
          <SweetAlert
            success
            style={{ display: "block", marginTop: "-100px" }}
            title="Success!"
            onConfirm={() =>{ hideAlert();closeModal(); }}
            onCancel={() => { hideAlert();closeModal(); }}
            confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
          >
            {msg}
          </SweetAlert>
        );
      };
      const errorAlert = (msg) => {
        setAlert(
          <SweetAlert
            error
            style={{ display: "block", marginTop: "-100px" }}
            title="Error!"
            onConfirm={() => hideErrorAlert()}
            onCancel={() => hideErrorAlert()}
            confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
          >
            {msg}
            <br />
            For Details Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}!
          </SweetAlert>
        );
      };
      const hideAlert = () => {
        closeModal();
        setAlert(null);
      };
      const hideErrorAlert = () => {
        setAlert(null);
      };
  const handleChange = (event) => {
    event.persist();

    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        [event.target.name]: event.target.value.toUpperCase(),
      },
    }));
  };
  const findMatch = (a,b) => a.reduce((acc,c) => {
    acc.total_match = a.filter(x => b.includes(x)).length
    acc.not_match = a.filter(x => !b.includes(x))
    return acc
  }, {total_match: 0})
  

  const handleFileChange = (event) => {
    let file = event.target.files[0];
    const allowedTypes = ['application/vnd.openxmlformats-officedocument.spreadsheetml.sheet','application/vnd.openxmlformats-officedocument.wordprocessingml.template', 'application/vnd.openxmlformats-officedocument.wordprocessingml.template', 'application/vnd.openxmlformats-officedocument.spreadsheetml.template', 'application/vnd.openxmlformats-officedocument.presentationml.template', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document','application/vnd.ms-excel'];
     if (findMatch(allowedTypes, [file.type]).total_match === 0) {
     errorAlert("Only  docx, dotx, xlsx, xltx, pptx, potx  Files Accepted");
      // $("#fileUpload").val("");
      document.getElementById("fileUpload").value = "";
      return false;
    } else {
      setFormState((formState) => ({
        ...formState,
        values: {
          ...formState.values,
          [event.target.name]: file,
        },
      }));
    }
  };
  function closeModal() {
    document.getElementById("fileUpload").value = "";
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        cabinate: null,
        drawer: null,
        fileUpload: null,
        fileInitComments: "",
      },
      errors: {
        ...formState.errors,
        cabinate: "",
        drawer:"",
        fileUpload: "",
        fileInitComments: "",
      },
    }));
    props.closeModal();
  }
 const calculateMd5 = (file, callback) => {
    try {
      var reader = new FileReader();
      reader.readAsArrayBuffer(file);
      reader.onloadend = function() {
        var wordArray = CryptoJS.lib.WordArray.create(reader.result),
          hash = CryptoJS.MD5(wordArray).toString();
        // or CryptoJS.SHA256(wordArray).toString(); for SHA-2
        callback(hash);
      };
    } catch (err) {
      callback(err);
    }
  }
  const handleRegister = (e) => {
    e.preventDefault();
    setFormState((formState) => ({
      ...formState,
      isRegistering: true,
    }));
    let cabinate;
    let drawer;
    let fileUpload;
    const Check = require("is-null-empty-or-undefined").Check;
    var error = false;
    if (!Check(formState.values.fileUpload)) {
      fileUpload = "success";
    } else {
      fileUpload = "error";
      error = true;
    }
    
    if (!Check(formState.values.cabinate)) {
      cabinate = "success";
    } else {
      cabinate = "error";
      error = true;
    }

    if (!Check(formState.values.drawer)) {
      drawer = "success";
    } else {
      drawer = "error";
      error = true;
    }


    setFormState((formState) => ({
      ...formState,
      errors: {
        ...formState.errors,
        cabinate: cabinate,
        drawer: drawer,
        fileUpload: fileUpload
      },
    }));
    if (error) {
      setFormState((formState) => ({
        ...formState,
        isRegistering: false,
      }));
      return false;
    } else {
    
      let comments = "";
      if (!Check(formState.values.fileInitComments)) {
        comments = formState.values.fileInitComments;
      } else {
        comments = "First version upload";
      }
      let msg = "";
      let Token = localStorage.getItem("cooljwt");
      let decoded = jwt.decode(Token);
      const userName = decoded.loginName;

      const fileName = formState.values.fileUpload.name.split('.')[0];
      const fileType = formState.values.fileUpload.name.substr(formState.values.fileUpload.name.lastIndexOf('.') + 1);
      var bodyFormData = new FormData();
      calculateMd5(formState.values.fileUpload, (hash, err) => {
        if (hash) {
          bodyFormData.append("files", formState.values.fileUpload);
          bodyFormData.append("loginname", userName);
          bodyFormData.append("metainfo", formState.values.cabinate+'/'+formState.values.drawer);
          bodyFormData.append("istemplate", false);
          bodyFormData.append("ispublic", false);
          bodyFormData.append("fileHash", hash);
          bodyFormData.append('locationID', decoded.locationID);

         

          axios({
            method: "post",
            url: `${process.env.REACT_APP_LDOCS_API_FILE_UPLOAD_URL}/api/files/upload`,
            data: bodyFormData,
            headers: { "Content-Type": "multipart/form-data",
            //cooljwt: Token 
          },
          })
            .then((response) => {
              console.log(response);
              axios({
                method: "post",
                url: `${process.env.REACT_APP_LDOCS_API_URL}/file/saveDocuments`,
                data: {
                  "accessGroup":[],
                  "accessUser":[],
                  "authorType":"NONE",
                  "authorAlias":"NONE",
                  "fileName":fileName,
                  "fileId":`${hash}-${userName}-${formState.values.fileUpload.name}`,
                  "filePath":`${formState.values.cabinate}//${formState.values.drawer}`,
                  "fileType":fileType,
                  "fileHash":hash,
                  "fileOwner":userName,
                  'locationID': decoded.locationID,
                  "fileInitComments":comments,
                  "fileInitClassification":"PRIVATE",
                  "fileInitSecrecy":"NONE",
                  "discardFile":false,
                  "isTemplate":false,
                  "parentHash":"",
                  "version":"",
                  "accessGroupd":"",
                  "fileInitDate":"",
                  "accessTeam":[],
                  "accessdept":[],
                  "accessComp":[],
                  "accessOrg":[],
                  "fileTags":[]
                },
                headers: { "Content-Type": "application/json",
                cooljwt: Token 
              },
              })
                .then((response) => {
                  props.getCabinats();
                  console.log(response);
                  setFormState((formState) => ({
                    ...formState,
                    isRegistering: false,
                  }));
                  successAlert('File has been Uploaded');
                });
              });
        }
      });
     


     

     // }
    //   if (err) errorAlert("Failed to create file hash");
    // });
  }
};



  return (
    <GridContainer>
      {alert}
      <GridItem xs={12} sm={12} md={12}>
        <Card>
          <CardHeader color="info" icon>
            <CardIcon color="info">
              <h4 className={classes.cardTitle}>Upload File</h4>
            </CardIcon>
          </CardHeader>
          <CardBody>
            <form onSubmit={handleRegister}>
              <GridContainer>
                <GridItem
                  xs={12}
                  sm={12}
                  md={12}
                  lg={12}
                  style={{ marginTop: "20px", marginBottom: "20px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.fileUpload === "error"}
                    helperText={
                      formState.errors.fileUpload === "error"
                        ? "Valid File Upload is required"
                        : null
                    }
                    label="Select a File to upload"
                    InputLabelProps={{
                      shrink: true,
                    }}
                    id="fileUpload"
                    name="fileUpload"
                    onChange={(event) => {
                      handleFileChange(event);
                    }}
                    type="file"
                    accept=".doc,.docx,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={6}
                  lg={6}
                  style={{ marginBottom: "20px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.cabinate === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.cabinate === "error"
                        ? "Please select a Cabinate"
                        : null
                    }
                    label="Cabinate"
                    name="cabinate"
                    onChange={(event) => {
                      handleChange(event);
                      const selectedCabinateName = event.target.value;
                      const selectedCabinate = props.Cabinats.find(cabinate=> cabinate.name.toUpperCase() == selectedCabinateName);
                      setDrawers(selectedCabinate.children);
                    }}
                    select
                    value={formState.values.cabinate || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose File Type
                    </MenuItem>

                    {props.Cabinats.map((cabinate, index) => {
                      return (
                        <MenuItem key={index} value={cabinate.name.toUpperCase()}>
                          {cabinate.name.toUpperCase()}
                        </MenuItem>
                      );
                    })}
                  </TextField>
                </GridItem>
                <GridItem 
                  xs={12}
                  sm={12}
                  md={6}
                  lg={6}
                  style={{ marginBottom: "20px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.drawer === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.drawer === "error"
                        ? "Please select Drawer"
                        : null
                    }
                    label="Drawer"
                    name="drawer"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    select
                    value={formState.values.drawer || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose Drawer
                    </MenuItem>

                    {drawers.map((classif, index) => {
                      return (
                        <MenuItem key={index} value={classif.name.toUpperCase()}>
                          {classif.name.toUpperCase()}
                        </MenuItem>
                      );
                    })}
                  </TextField>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={12}
                  lg={12}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.fileInitComments === "error"}
                    helperText={
                      formState.errors.fileInitComments === "error"
                        ? "Valid Comments is required"
                        : null
                    }
                    label="File Comments"
                    id="fileInitComments"
                    name="fileInitComments"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    InputProps={{
                      endAdornment: (
                        <InputAdornment position="end">
                          <MessageIcon />
                        </InputAdornment>
                      ),
                    }}
                    type="text"
                    value={formState.values.fileInitComments || ""}
                  />
                </GridItem>
              </GridContainer>

              <Button
                color="info"
                className={classes.registerButton}
                round
                type="submit"
              >
                Upload File
              </Button>
              {formState.isRegistering ? (
                <CircularProgress disableShrink />
              ) : (
                ""
              )}
              <Button
                color="danger"
                className={classes.registerButton}
                onClick={closeModal}
                round
              >
                Close
              </Button>
            </form>
          </CardBody>
        </Card>
      </GridItem>
    </GridContainer>
  );
}
