import React, { useState, useEffect } from "react";
// @material-ui/core components
import {
  MenuItem,
  makeStyles,
  CircularProgress,
  TextField,
  Input,
  InputAdornment,
} from "@material-ui/core";
// core components
import MessageIcon from "@material-ui/icons/Message";

import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import jwt from "jsonwebtoken";
import CryptoJS from "crypto-js";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";

import { useSelector, useDispatch } from "react-redux";
//Redux Actions
import { sendNotification } from "actions";

const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

export default function Delete(props) {
  // register form

  
  const [isRegistering, setisRegistering] = useState(false);
      const classes = useStyles();
      const sweetClass = sweetAlertStyle();
      const [alert, setAlert] = React.useState(null);
      const dispatch = useDispatch();
      const successAlert = (msg) => {
        setAlert(
          <SweetAlert
            success
            style={{ display: "block", marginTop: "-100px" }}
            title="Success!"
            onConfirm={() => { hideAlert();}}
            onCancel={() => { hideAlert();}}
            confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
          >
            {msg}
          </SweetAlert>
        );
      };
      const errorAlert = (msg) => {
        setAlert(
          <SweetAlert
            error
            style={{ display: "block", marginTop: "-100px" }}
            title="Error!"
            onConfirm={() => hideErrorAlert()}
            onCancel={() => hideErrorAlert()}
            confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
          >
            {msg}
            <br />
            For Details Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}!
          </SweetAlert>
        );
      };
      const hideAlert = () => {
        closeModal();
        setAlert(null);
      };
      const hideErrorAlert = () => {
        setAlert(null);
      };
  

  function closeModal() {
    document.getElementById("fileUpload").value = "";
    
    props.closeModal();
  }

  function deletethisFile(){
    let Token = localStorage.getItem("cooljwt");
    let decoded = jwt.decode(Token);
    let loginName = decoded.loginName;
    let getFolderName = props.selectedFile.fileName.split("-");
    let folderName = getFolderName[getFolderName.length - 1].split('.')[0];
    var bodyData = {
      'userName':loginName,
      'isTemplate':props.selectedFile.isTemp,
      'isPublic':props.selectedFile.isPublic,
      'cname':props.selectedFile.cabinate,
      'dname':props.selectedFile.drawer,
      'folderName':folderName,
      'fileName':props.selectedFile.fileName
    };
    // axios({
    //   method: "delete",
    //   url: `${process.env.REACT_APP_LDOCS_API_FILE_URL}/api/deleteFile`,
    //   data: bodyData,
    //   headers: { "Content-Type": "application/json", cooljwt: Token},
    // })
    //   .then(({ data }) => {
        axios({
          method: "put",
          url: `${process.env.REACT_APP_LDOCS_API_URL}/files/markFileDeleted/${props.selectedFile.fileName}`,
          //headers: {cooljwt: Token},
        })
          .then(({ data }) => {
           console.log(data);
           props.getCabinats();
           props.clearFileData();
           //dispatch(sendNotification(folderName+ 'Template has been Marked as Delete', userName));
           successAlert('File Deleted Successful.');
           // dispatch({ type: "FILE_DELETE", response: [] });
          })
          .catch((error) => {
             let msg = typeof error.response != "undefined"
             ? error.response.data
             : error.message;
             //dispatch({ type: "FILE_DOWNLOAD", response: [] });
          });
        //dispatch({ type: "FILE_DELETE", response: downloadUrl });
      // })
      // .catch((error) => {
      //    let msg = typeof error.response != "undefined"
      //    ? error.response.data
      //    : error.message;
      //    //dispatch({ type: "FILE_DOWNLOAD", response: [] });
      // });
  }

  return (
    <GridContainer>
      {alert}
      <GridItem xs={12} sm={12} md={12}>
        <Card>
          <CardHeader color="info" icon>
            <CardIcon color="info">
              <h4 className={classes.cardTitle}>Delete Template</h4>
            </CardIcon>
          </CardHeader>
          <CardBody>
              <GridContainer>
                <GridItem
                  xs={12}
                  sm={12}
                  md={12}
                  lg={12}
                  style={{ marginTop: "20px", marginBottom: "20px" }}
                >
                  <TextField
                    fullWidth={true}
                    label="Selected File to Delete"
                    InputLabelProps={{
                      shrink: true,
                    }}
                    style={{
                        minWidth:600
                    }}
                    id="fileUpload"
                    name="fileUpload"
                    value={props.selectedFile.fileName}
                    type="Text"
                    disabled
                  />
                </GridItem>
              </GridContainer>

              <Button
                color="info"
                className={classes.registerButton}
                round
                onClick={()=>deletethisFile()}
              >
                DELETE Template
              </Button>
              {isRegistering ? (
                <CircularProgress disableShrink />
              ) : (
                ""
              )}
              <Button
                color="danger"
                className={classes.registerButton}
                onClick={closeModal}
                round
              >
                Close
              </Button>
          </CardBody>
        </Card>
      </GridItem>
    </GridContainer>
  );
}
