/*eslint-disable*/
import React, { useState, useEffect } from "react";
// @material-ui/core components
import {
  MenuItem,
  makeStyles,
  CircularProgress,
  TextField,
  Input,
  InputAdornment,
} from "@material-ui/core";
// core components
import MessageIcon from "@material-ui/icons/Message";

import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import jwt from "jsonwebtoken";
import CryptoJS from "crypto-js";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";

import { useSelector, useDispatch } from "react-redux";
//Redux Actions
import { sendNotification } from "actions";


const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

export default function DownloadFile(props) {
  // register form

  const [formState, setFormState] = useState({
    isRegistering: false,
    values: {
      cabinate:null,
      drawer:null,
      fileInitComments: "",
    },
    errors: {
      cabinate: "",
      drawer:null,
      fileInitComments: "",
    },
  });
  const [drawers, setDrawers] = useState([]);
      const classes = useStyles();
      const sweetClass = sweetAlertStyle();
      const [alert, setAlert] = React.useState(null);
      const dispatch = useDispatch();
      const successAlert = (msg) => {
        setAlert(
          <SweetAlert
            success
            style={{ display: "block", marginTop: "-100px" }}
            title="Success!"
            onConfirm={() => { hideAlert();}}
            onCancel={() => { hideAlert(); }}
            confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
          >
            {msg}
          </SweetAlert>
        );
      };
      const errorAlert = (msg) => {
        setAlert(
          <SweetAlert
            error
            style={{ display: "block", marginTop: "-100px" }}
            title="Error!"
            onConfirm={() => hideErrorAlert()}
            onCancel={() => hideErrorAlert()}
            confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
          >
            {msg}
            <br />
            For Details Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}!
          </SweetAlert>
        );
      };
      const hideAlert = () => {
        closeModal();
        setAlert(null);
      };
      const hideErrorAlert = () => {
        setAlert(null);
      };
  const handleChange = (event) => {
    event.persist();

    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        [event.target.name]: event.target.value.toUpperCase(),
      },
    }));
  };

  function closeModal() {
    document.getElementById("fileUpload").value = "";
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        cabinate: null,
        drawer: null,
        fileInitComments: "",
      },
      errors: {
        ...formState.errors,
        cabinate: "",
        drawer:"",
        fileInitComments: "",
      },
    }));
    props.closeModal();
  }

  const handleRegister = (e) => {
    e.preventDefault();
    setFormState((formState) => ({
      ...formState,
      isRegistering: true,
    }));
    let cabinate;
    let drawer;
    const Check = require("is-null-empty-or-undefined").Check;
    var error = false;

    
    if (!Check(formState.values.cabinate)) {
      cabinate = "success";
    } else {
      cabinate = "error";
      error = true;
    }

    if (!Check(formState.values.drawer)) {
      drawer = "success";
    } else {
      drawer = "error";
      error = true;
    }


    setFormState((formState) => ({
      ...formState,
      errors: {
        ...formState.errors,
        cabinate: cabinate,
        drawer: drawer,
      },
    }));
    if (error) {
      setFormState((formState) => ({
        ...formState,
        isRegistering: false,
      }));
      return false;
    } else {
    
      let comments = "";
      if (!Check(formState.values.fileInitComments)) {
        comments = formState.values.fileInitComments;
      } else {
        comments = "First version upload";
      }
      let msg = "";
      let Token = localStorage.getItem("cooljwt");
      let decoded = jwt.decode(Token);
      const userName = decoded.loginName;
      var bodyFormData = new FormData();
          bodyFormData.append("filename", props.selectedFile.fileName);
          bodyFormData.append("loginname", userName);
          bodyFormData.append("metainfo_old", props.selectedFile.drawerName);
          bodyFormData.append("metainfo_new", formState.values.cabinate+'/'+formState.values.drawer);
          bodyFormData.append("istemplate", true);
          bodyFormData.append("ispublic", props.ispublic);
          bodyFormData.append("fileHash", props.selectedFile.hash);
          bodyFormData.append("fileNameNew", props.selectedFile.fileName.split('.').slice(0, -1).join('.'));
         

          axios({
            method: "post",
            url: `${process.env.REACT_APP_LDOCS_API_FILE_UPLOAD_URL}/api/files/download`,
            data: bodyFormData,
            headers: { "Content-Type": "multipart/form-data",
            //cooljwt: Token 
          },
          })
            .then((response) => {
              console.log(response);
              axios({
                method: "post",
                url: `${process.env.REACT_APP_LDOCS_API_URL}/file/saveDocuments`,
                data: {
                  "accessGroup":[],
                  "accessUser":[],
                  "authorType":"NONE",
                  "authorAlias":"NONE",
                  "fileName":props.selectedFile.fileName,
                  "fileId":"",
                  "filePath":`${formState.values.cabinate}\\${formState.values.drawer}`,
                  "fileType":"",
                  "fileHash":props.selectedFile.hash,
                  "fileOwner":userName,
                  "fileInitComments":comments,
                  "fileInitClassification":"PRIVATE",
                  "fileInitSecrecy":"NONE",
                  "discardFile":false,
                  "isTemplate":false,
                  "parentHash":"",
                  "version":"",
                  "accessGroupd":"",
                  "fileInitDate":"",
                  "accessTeam":[],
                  "accessdept":[],
                  "accessComp":[],
                  "accessOrg":[],
                  "fileTags":[]
                },
                headers: { "Content-Type": "application/json",
                cooljwt: Token 
              },
              })
                .then((response) => {
                  console.log(response);
                  setFormState((formState) => ({
                    ...formState,
                    isRegistering: false,
                  }));
                  dispatch(sendNotification(props.selectedFile.fileName +'Template has been Moved to User Directory', userName));
                  successAlert('Template has been moved to user directory');
                });
              });

     


     

     // }
    //   if (err) errorAlert("Failed to create file hash");
    // });
  }
};

useEffect(()=>{
console.log(props.selectedFile);
},[])

  return (
    <GridContainer>
      {alert}
      <GridItem xs={12} sm={12} md={12}>
        <Card>
          <CardHeader color="info" icon>
            <CardIcon color="info">
              <h4 className={classes.cardTitle}>Use Template</h4>
            </CardIcon>
          </CardHeader>
          <CardBody>
            <form onSubmit={handleRegister}>
              <GridContainer>
                <GridItem
                  xs={12}
                  sm={12}
                  md={12}
                  lg={12}
                  style={{ marginTop: "20px", marginBottom: "20px" }}
                >
                  <TextField
                    fullWidth={true}
                    label="Selected File to Move"
                    InputLabelProps={{
                      shrink: true,
                    }}
                    id="fileUpload"
                    name="fileUpload"
                    value={props.selectedFile.fileName}
                    type="Text"
                    disabled
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={6}
                  lg={6}
                  style={{ marginBottom: "20px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.cabinate === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.cabinate === "error"
                        ? "Please select a Cabinate"
                        : null
                    }
                    label="Cabinate"
                    name="cabinate"
                    onChange={(event) => {
                      handleChange(event);
                      const selectedCabinateName = event.target.value;
                      const selectedCabinate = props.Cabinats.find(cabinate=> cabinate.name.toUpperCase() == selectedCabinateName);
                      setDrawers(selectedCabinate.children);
                    }}
                    select
                    value={formState.values.cabinate || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose File Type
                    </MenuItem>

                    {props.Cabinats.map((cabinate, index) => {
                      return (
                        <MenuItem key={index} value={cabinate.name.toUpperCase()}>
                          {cabinate.name.toUpperCase()}
                        </MenuItem>
                      );
                    })}
                  </TextField>
                </GridItem>
                <GridItem 
                  xs={12}
                  sm={12}
                  md={6}
                  lg={6}
                  style={{ marginBottom: "20px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.drawer === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.drawer === "error"
                        ? "Please select Drawer"
                        : null
                    }
                    label="Drawer"
                    name="drawer"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    select
                    value={formState.values.drawer || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose Drawer
                    </MenuItem>

                    {drawers.map((classif, index) => {
                      return (
                        <MenuItem key={index} value={classif.name.toUpperCase()}>
                          {classif.name.toUpperCase()}
                        </MenuItem>
                      );
                    })}
                  </TextField>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={12}
                  lg={12}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.fileInitComments === "error"}
                    helperText={
                      formState.errors.fileInitComments === "error"
                        ? "Valid Comments is required"
                        : null
                    }
                    label="File Comments"
                    id="fileInitComments"
                    name="fileInitComments"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    InputProps={{
                      endAdornment: (
                        <InputAdornment position="end">
                          <MessageIcon />
                        </InputAdornment>
                      ),
                    }}
                    type="text"
                    value={formState.values.fileInitComments || ""}
                  />
                </GridItem>
              </GridContainer>

              <Button
                color="info"
                className={classes.registerButton}
                round
                type="submit"
              >
                Copy Template
              </Button>
              {formState.isRegistering ? (
                <CircularProgress disableShrink />
              ) : (
                ""
              )}
              <Button
                color="danger"
                className={classes.registerButton}
                onClick={closeModal}
                round
              >
                Close
              </Button>
            </form>
          </CardBody>
        </Card>
      </GridItem>
    </GridContainer>
  );
}
