import React, {useEffect, useState} from 'react';
import RLDD from 'react-list-drag-and-drop/lib/RLDD';
import TableCell from '@material-ui/core/TableCell';
import Typography from '@material-ui/core/Typography';
import TableRow from '@material-ui/core/TableRow';
import Table from '@material-ui/core/Table';
import TableContainer from '@material-ui/core/TableContainer';
import Paper from '@material-ui/core/Paper';
import TableHead from '@material-ui/core/TableHead';
import TableBody from '@material-ui/core/TableBody';
import { makeStyles } from '@material-ui/core/styles';
import IconButton from '@material-ui/core/IconButton';
import DeleteIcon from '@material-ui/icons/Delete';
import FormControlLabel from '@material-ui/core/FormControlLabel';
import Switch from '@material-ui/core/Switch';
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import MoreVertIcon from '@material-ui/icons/MoreVert';



const useStyles = makeStyles({
    table: {
      minWidth: '100%',
      border:1
    },
    TableCell:{
        width:'10%'
    },
    TableRow:{
        cursor:'pointer',
        background:'white',
        border:1, width:'100%'
    }
  });

export default function DragAndDrop(props){
    const classes = useStyles();
    const [list , setList]= useState(props.list);
    const [isEdit, setIsEdit] = useState(false);
    const isViewing = props.isViewing;
    const handleChange = (event) => {
        setIsEdit(!isEdit);
      };

    const removeFromList = (i) => {
        var arr = list.filter(function(value, index, arr){
            return index !== i;
        });
        console.log(arr);
        setList(arr);
    }

    const handleRLDDChange = (reorderedItems) => {
        setList(reorderedItems);
     }

    useEffect(()=>{
       props.onChange(list);
       console.log(list);
    },[list]);


    const itemRenderer = (item, index) => {
        return (
            <Table>
            <TableBody>
            <TableRow hover key={item.id} className={classes.TableRow}>
                <TableCell className={classes.TableCell}><MoreVertIcon/></TableCell>
                <TableCell className={classes.TableCell}>{index+1}</TableCell>
                <TableCell className={classes.TableCell}>{item.Desigination}</TableCell>
                <TableCell className={classes.TableCell}>{item.Organization}</TableCell>
                <TableCell className={classes.TableCell}>{item.Company}</TableCell>
                <TableCell className={classes.TableCell}>{item.Event}</TableCell>
                <TableCell className={classes.TableCell}>{item.RejectionBehaviour.toUpperCase()}</TableCell>
                <TableCell className={classes.TableCell}>{item.TimeOutPeriod}</TableCell>
                <TableCell className={classes.TableCell}>{item.NotificationPeriod}</TableCell>
                {!isViewing ?
                    <TableCell className={classes.TableCell}>
                    <IconButton onClick={()=>removeFromList(index)} aria-label="delete" color="primary">
                    <DeleteIcon />
                    </IconButton>
                    </TableCell>
                : ''} 
            </TableRow>
            </TableBody>
            </Table>
        );
    }



    return (
        <Paper style={{padding:10}}>
            <GridContainer>
            <GridItem xs={9}>
                <Typography variant="h5">WORKFLOW SEQUENCE</Typography>
            </GridItem>
            {!isViewing ?    
            <GridItem  xs={3}>
            <FormControlLabel
            control={
            <Switch
                checked={isEdit}
                onChange={handleChange}
                name="edit"
                color="primary"
            />
        }
        label="EDIT / RE-ORDER"
        />
        </GridItem>
        :""}
        <GridItem xs={12}>
        {isEdit ? 
              <RLDD
                cssClasses="example"
                items={list}
                itemRenderer={itemRenderer.bind(this)}
                onChange={handleRLDDChange.bind(this)}
            />  
            :
            <TableContainer>
            <Table className={classes.table} aria-label="simple table">
            <TableHead>
                    <TableRow className={classes.TableRow}>
                    <TableCell className={classes.TableCell}>ID</TableCell>
                    <TableCell className={classes.TableCell}>DESIGNTION</TableCell>
                    <TableCell className={classes.TableCell}>ORGANIZATION</TableCell>
                    <TableCell className={classes.TableCell}>COMPANY</TableCell>
                    <TableCell className={classes.TableCell}>ROLE</TableCell>
                    <TableCell className={classes.TableCell}>REVIEW PROCEDURE</TableCell>
                    <TableCell className={classes.TableCell}>DUE IN</TableCell>
                    <TableCell className={classes.TableCell}>REMINDER (HRS)</TableCell>
                    {!isViewing ?
                    <TableCell className={classes.TableCell}>ACTIONS</TableCell>
                    :""}
                </TableRow>
            </TableHead>
            <TableBody style={{paddingBottom:5}}>
                {list.map((item, index)=>{
                    return (
                    <TableRow key={item.id}>
                        <TableCell className={classes.TableCell}>{index+1}</TableCell>
                        <TableCell className={classes.TableCell}>{item.Desigination}</TableCell>
                        <TableCell className={classes.TableCell}>{item.Organization}</TableCell>
                        <TableCell className={classes.TableCell}>{item.Company}</TableCell>
                        <TableCell className={classes.TableCell}>{item.Event}</TableCell>
                        <TableCell className={classes.TableCell}>{item.RejectionBehaviour.toUpperCase()}</TableCell>
                        <TableCell className={classes.TableCell}>{item.TimeOutPeriod}</TableCell>
                        <TableCell className={classes.TableCell}>{item.NotificationPeriod}</TableCell>
                        {!isViewing ?
                            <TableCell className={classes.TableCell}>
                            <IconButton  aria-label="delete"  color="primary" disabled={!isEdit}>
                            <DeleteIcon />
                            </IconButton>
                            </TableCell>
                        :""}
                    </TableRow>
                )}
                )}
            </TableBody>
            </Table>
            </TableContainer>
            }
        </GridItem>
        </GridContainer>     
      </Paper>
    );
  

}

