/*eslint-disable*/
import React, { useState } from "react";
// @material-ui/core components
import { TextField, makeStyles, CircularProgress, Slide, Dialog } from "@material-ui/core";
// core components
import { useDispatch } from "react-redux";
import { getOrganizations } from "actions";
import SweetAlert from "react-bootstrap-sweetalert";
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import axios from "axios";
import defaultAvatar from "assets/img/placeholder.jpg";
import { Animated } from "react-animated-css";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import ImageUpload from "./ImageUpload.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";
import OtpCheck from "../Authorization/OtpCheck";

var Token = localStorage.getItem("cooljwt");
const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

const Transition = React.forwardRef(function Transition(props, ref) {
  return <Slide direction="down" ref={ref} {...props} />;
});

export default function ViewOrg(props) {
  // register form
  const dispatch = useDispatch();
const [animateTable, setAnimateTable] = React.useState(true);
const [otpModal, setotpModal] = React.useState(false);
const [OTP, setOTP] = React.useState("");
  const [formState, setFormState] = useState({
    isLoading: true,
    isRegistering: false,
    values: {
      name: props.orgDetail.organizationName,
      countryOfOrigin: props.orgDetail.countryOfOrigin,
      tradeLicenseNumber: props.orgDetail.tradeLicenseNumber,
      pbr: props.orgDetail.primaryBusinessRepresentative,
      pbrEmail: props.orgDetail.primaryBusinessRepresentativeEmail,
      pbrloginname: props.orgDetail.primaryBusinessRepresentativeLoginName,
      pbrcellnumber: props.orgDetail.primaryBusinessRepresentativeCellNumber,
      pbrothernumber: props.orgDetail.primaryBusinessRepresentativeOtherNumber,
      sbremail: props.orgDetail.secondaryBusinessRepresentativeEmail,
      sbrcellnumber: props.orgDetail.secondaryBusinessRepresentativeCellNumber,
      sbrothernumber: props.orgDetail.secondaryBusinessRepresentativeOtherNumber,
      referenceTicket: props.orgDetail.referenceTicket,
      created: props.orgDetail.created,
      displayLogo: "",
      tradeLicenseImage: "",
    },
    errors: {
      name: "",
      countryOfOrigin: "",
      tradeLicenseNumber: "",
      pbr: "",
      pbrEmail: "",
      pbrloginname: "",
      pbrcellnumber: "",
      pbrothernumber: "",
      sbremail: "",
      sbrcellnumber: "",
      sbrothernumber: "",
      referenceTicket: "",
    },
  });
    const getOrgDetails = () => {
    axios
      .get(
        `${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/orglist/${props.orgDetail.organizationName}`
      )
      .then((response) => {
        let org = response.data;
        var base64Flag = "";
        let tradeLicenseImage = "";
        let displayLogo = "";
        if (typeof org.tradeLicenseImage != "undefined") {
          base64Flag = `data:${org.tradeLicenseImageT};base64,`;
          tradeLicenseImage = base64Flag + org.tradeLicenseImage;

          base64Flag = `data:${org.displayLogoT};base64,`;
          displayLogo = base64Flag + org.displayLogo;
        } else {
          tradeLicenseImage = defaultAvatar;
          displayLogo = defaultAvatar;
        }
        
        setFormState((formState) => ({
          ...formState,
          isLoading: false,
          values: {
            ...formState.values,
            displayLogo: displayLogo,
            tradeLicenseImage: tradeLicenseImage,
          },
        }));
      })
      .catch((error) => {
        setFormState((formState) => ({
          ...formState,
          isLoading: false,
          values: {
            ...formState.values,
            displayLogo: "",
            tradeLicenseImage: "",
          },
        }));
        console.log(
          typeof error.response != "undefined"
            ? error.response.data
            : error.message
        );
      });
    };
    React.useEffect(() => {
      getOrgDetails();
    }, []);
  const closeModal = () => {
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        name: "",
        countryOfOrigin: "",
        tradeLicenseNumber: "",
        pbr: "",
        pbrEmail: "",
        pbrloginname: "",
        pbrcellnumber: "",
        pbrothernumber: "",
        sbremail: "",
        sbrcellnumber: "",
        sbrothernumber: "",
        referenceTicket: "",
      },
    }));
    props.closeModal();
  };
  const handleChange = (event) => {
    event.persist();

    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        [event.target.name]: event.target.value.toUpperCase(),
      },
    }));
  };
  const verifyEmail = (value) => {
    var emailRex = /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
    if (emailRex.test(value)) {
      return true;
    }
    return false;
  };
  const [tradeFile, setTradeFile] = useState(null);
  const [displayLogo, setDisplayLogo] = useState(null);
  const handleImageChange = (file, status, imageName) => {

    if (status == 1) {
      if (imageName == "tradeLicenseImage") {
        setTradeFile(file);
      } else if ("displayLogo") {
        setDisplayLogo(file);
      }
      
    } else {
      if (imageName == "tradeLicenseImage") {
        setTradeFile(null);
      } else if ("displayLogo") {
        setDisplayLogo(null);
      }
    }
  };
  const sweetClass = sweetAlertStyle();
      const [alert, setAlert] = React.useState(null);
      const successAlert = (msg) => {
        setAlert(
          <SweetAlert
            success
            style={{ display: "block", marginTop: "-100px" }}
            title="Success!"
            onConfirm={() => hideAlert()}
            onCancel={() => hideAlert()}
            confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
          >
            {msg}
          </SweetAlert>
        );
      };
      const errorAlert = (msg) => {
        setAlert(
          <SweetAlert
            error
            style={{ display: "block", marginTop: "-100px" }}
            title="Error!"
            onConfirm={() => hideErrorAlert()}
            onCancel={() => hideErrorAlert()}
            confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
          >
            {msg ? msg : "Unable To Update Organization Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}"}
          </SweetAlert>
        );
      };
  const hideAlert = () => {
        closeModal();
        setAlert(null);
      };
  const hideErrorAlert = () => {
    setAlert(null);
  };
  const handleUpdate = () => {

    let name;
    let countryOfOrigin;
    let tradeLicenseNumber;
    let pbr;
    let pbrEmail;
    let pbrloginname;
    let pbrcellnumber;
    let sbremail;
    let sbrcellnumber;
    let referenceTicket;
      const Check = require("is-null-empty-or-undefined").Check;
      var error = false;

      if (!Check(formState.values.name)) {
        name = "success";
      } else {
        name = "error";
        error = true;
       }
      if (!Check(formState.values.countryOfOrigin)) {
        countryOfOrigin = "success";
      } else {
        countryOfOrigin = "error";
        error = true;
      }
      if (!Check(formState.values.tradeLicenseNumber)) {
        tradeLicenseNumber = "success";
      } else {
        tradeLicenseNumber = "error";
        error = true;
      }
      if (!Check(formState.values.pbr)) {
        pbr = "success";
      } else {
        pbr = "error";
        error = true;
      }
      if (!Check(formState.values.pbrEmail)) {
        if (verifyEmail(formState.values.pbrEmail)) {
          pbrEmail = "success";
        } else {
          pbrEmail = "error";
          error = true;
        }
      } else {
        pbrEmail = "error";
        error = true;
    }
     if (!Check(formState.values.pbrloginname)) {
       pbrloginname = "success";
     } else {
       pbrloginname = "error";
       error = true;
     }
     if (!Check(formState.values.pbrcellnumber)) {
       pbrcellnumber = "success";
     } else {
       pbrcellnumber = "error";
       error = true;
     }
      if (!Check(formState.values.sbremail)) {
        if (verifyEmail(formState.values.sbremail)) {
          sbremail = "success";
        } else {
          sbremail = "error";
          error = true;
        }
      } else {
        sbremail = "error";
        error = true;
    }
    if (!Check(formState.values.sbrcellnumber)) {
      sbrcellnumber = "success";
    } else {
      sbrcellnumber = "error";
      error = true;
    }
    if (!Check(formState.values.referenceTicket)) {
      referenceTicket = "success";
    } else {
      referenceTicket = "error";
      error = true;
    }
    setFormState((formState) => ({
      ...formState,
      errors: {
        ...formState.errors,
          name: name,
          countryOfOrigin: countryOfOrigin,
          tradeLicenseNumber: tradeLicenseNumber,
          pbr: pbr,
          pbrEmail: pbrEmail,
          pbrloginname: pbrloginname,
          pbrcellnumber: pbrcellnumber,
          sbremail: sbremail,
          sbrcellnumber: sbrcellnumber,
          referenceTicket: referenceTicket,
      }
    }));
    if (error) {
      setFormState((formState) => ({
        ...formState,
        isRegistering: false,
      }));
      errorAlert("Invalid Details!");
      return false;
    } else { 
      if(!OTP){
        setotpModal(true);
        return false;
      }
      setFormState((formState) => ({
        ...formState,
        isRegistering: true,
      }));
      var bodyFormData = new FormData();
      bodyFormData.append("organizationName", formState.values.name); 
      bodyFormData.append("countryOfOrigin", formState.values.countryOfOrigin); 
      bodyFormData.append("tradeLicenseNumber", formState.values.tradeLicenseNumber); 
      bodyFormData.append("displayLogo", displayLogo);
      bodyFormData.append("tradeLicenseImage", tradeFile);
      bodyFormData.append(
        "primaryBusinessRepresentative",
        formState.values.pbr
      );
      bodyFormData.append(
        "primaryBusinessRepresentativeEmail",
        formState.values.pbrEmail
      );
      bodyFormData.append(
        "primaryBusinessRepresentativeLoginName",
        formState.values.pbrloginname
      );
      bodyFormData.append(
        "primaryBusinessRepresentativeCellNumber",
        formState.values.pbrcellnumber
      );
      bodyFormData.append(
        "primaryBusinessRepresentativeOtherNumber",
        formState.values.pbrothernumber
      );
      bodyFormData.append(
        "secondaryBusinessRepresentativeEmail",
        formState.values.sbremail
      );
      bodyFormData.append(
        "secondaryBusinessRepresentativeCellNumber",
        formState.values.sbrcellnumber
      );
      bodyFormData.append(
        "secondaryBusinessRepresentativeOtherNumber",
        formState.values.sbrothernumber
      );
      bodyFormData.append("referenceTicket", formState.values.referenceTicket);
      bodyFormData.append("otp", OTP);
      let msg = "";
       axios({
         method: "patch",
         url: `${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/updorg`,
         data: bodyFormData,
         headers: { "Content-Type": "multipart/form-data", "cooljwt": Token },
       })
         .then((response) => {
          dispatch(getOrganizations());
          setFormState((formState) => ({
            ...formState,
            isRegistering: false,
          }));
          setOTP("");
          setTradeFile(null);
           setDisplayLogo(null);
           props.getOrganizations();
           msg = "Organization Updated Successfully!";
          successAlert(msg);
         })
         .catch((error) => {
           setFormState((formState) => ({
             ...formState,
             isRegistering: false,
           }));
           msg =
             typeof error.response != "undefined"
               ? error.response.data
               : error.message;
           errorAlert(msg);
         });
    }
  }
  React.useEffect(() => {
    if (!otpModal) {
      const Check = require("is-null-empty-or-undefined").Check;
      if (!Check(OTP)) {
        handleUpdate();
      }
    }
  }, [otpModal])
  const setOtpValue = (value) => {
    setOTP(value);
    setotpModal(false);  
  }
  const classes = useStyles();
    return (
      <Animated
        animationIn="bounceInRight"
        animationOut="bounceOutLeft"
        animationInDuration={1000}
        animationOutDuration={1000}
        isVisible={animateTable}
      >
        {alert}
        {otpModal ?
        <Dialog
            classes={{
              root: classes.center + " " + classes.modalRoot,
              paper: classes.modal,
            }}
            fullWidth={true}
            maxWidth={"xs"}
            open={otpModal}
            TransitionComponent={Transition}
            keepMounted
            onClose={() => setotpModal(false)}
            aria-labelledby="classic-modal-slide-title"
            aria-describedby="classic-modal-slide-description"
          >
               <OtpCheck setOtpValue={setOtpValue} /> 
          </Dialog>
        : ""}
        <GridContainer>
          <GridItem xs={12} sm={12} md={12}>
            <Card>
              <CardHeader color="info" icon>
                <CardIcon color="info">
                  <h4 className={classes.cardTitle}>Organization Details</h4>
                </CardIcon>
              </CardHeader>
              <CardBody>
                <GridContainer>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      label="Organization Name"
                      id="name"
                      name="name"
                      type="text"
                      disabled={true}
                      value={formState.values.name || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.countryOfOrigin === "error"}
                      helperText={
                        formState.errors.countryOfOrigin === "error"
                          ? "Valid country of origin is required"
                          : null
                      }
                      label="Country Of Origin"
                      id="countryOfOrigin"
                      name="countryOfOrigin"
                      type="text"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.countryOfOrigin || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.tradeLicenseNumber === "error"}
                      helperText={
                        formState.errors.tradeLicenseNumber === "error"
                          ? "Valid Trade License Number is required"
                          : null
                      }
                      label="Trade License Number"
                      id="tradeLicenseNumber"
                      name="tradeLicenseNumber"
                      type="text"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.tradeLicenseNumber || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.pbr === "error"}
                      helperText={
                        formState.errors.pbr === "error"
                          ? "Valid Primary Business Representative is required"
                          : null
                      }
                      label="Primary Business Representative"
                      id="pbr"
                      name="pbr"
                      type="text"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.pbr || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.pbrEmail === "error"}
                      helperText={
                        formState.errors.pbrEmail === "error"
                          ? "Valid PBR Email is required"
                          : null
                      }
                      label="PBR Email"
                      id="pbrEmail"
                      name="pbrEmail"
                      type="email"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.pbrEmail || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.pbrloginname === "error"}
                      helperText={
                        formState.errors.pbrloginname === "error"
                          ? "Valid PBR Login Name is required"
                          : null
                      }
                      label="PBR Login Name"
                      id="pbrloginname"
                      name="pbrloginname"
                      type="text"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.pbrloginname || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.pbrcellnumber === "error"}
                      helperText={
                        formState.errors.pbrcellnumber === "error"
                          ? "Valid PBR Cell Number is required"
                          : null
                      }
                      label="PBR Cell Number"
                      id="pbrcellnumber"
                      name="pbrcellnumber"
                      type="text"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.pbrcellnumber || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.pbrothernumber === "error"}
                      helperText={
                        formState.errors.pbrothernumber === "error"
                          ? "Valid PBR Other Number is required"
                          : null
                      }
                      label="PBR Other Number"
                      id="pbrothernumber"
                      name="pbrothernumber"
                      type="text"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.pbrothernumber || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.sbremail === "error"}
                      helperText={
                        formState.errors.sbremail === "error"
                          ? "Valid SBR Email is required"
                          : null
                      }
                      label="SBR Email"
                      id="sbremail"
                      name="sbremail"
                      type="email"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.sbremail || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.sbrcellnumber === "error"}
                      helperText={
                        formState.errors.sbrcellnumber === "error"
                          ? "Valid SBR Cell Number is required"
                          : null
                      }
                      label="SBR Cell Number"
                      id="sbrcellnumber"
                      name="sbrcellnumber"
                      type="text"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.sbrcellnumber || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.sbrothernumber === "error"}
                      helperText={
                        formState.errors.sbrothernumber === "error"
                          ? "Valid SBR Other Number is required"
                          : null
                      }
                      label="SBR Other Number"
                      id="sbrothernumber"
                      name="sbrothernumber"
                      type="text"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.sbrothernumber || ""}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{ marginTop: "10px", marginBottom: "10px" }}
                  >
                    <TextField
                      fullWidth={true}
                      error={formState.errors.referenceTicket === "error"}
                      helperText={
                        formState.errors.referenceTicket === "error"
                          ? "Valid Reference Ticket is required"
                          : null
                      }
                      label="Reference Ticket"
                      id="referenceTicket"
                      name="referenceTicket"
                      type="text"
                      onChange={(event) => {
                        handleChange(event);
                      }}
                      disabled={props.Updating ? false : true}
                      value={formState.values.referenceTicket || ""}
                    />
                  </GridItem>
                  {formState.isLoading ? (
                    <React.Fragment>
                      Loading Images...&nbsp;&nbsp;
                      <CircularProgress disableShrink />
                    </React.Fragment>
                  ) : (
                    <React.Fragment>
                      <GridItem xs={12} sm={12} md={6} lg={6}>
                      <legend>Trade License Image</legend>
                        {props.Updating ? 
                  <ImageUpload
                    addButtonProps={{
                      color: "info",
                      round: true,
                    }}
                    changeButtonProps={{
                      color: "info",
                      round: true,
                    }}
                    removeButtonProps={{
                      color: "danger",
                      round: true,
                    }}
                    oldImage={formState.values.tradeLicenseImage}
                    name="tradeLicenseImage"
                    buttonId="removeTradeImage"
                    handleImageChange={handleImageChange}
                  /> :
                  <div className="fileinput text-center">
                    <div className="thumbnail">
                      <img
                        src={formState.values.tradeLicenseImage}
                        alt="..."
                      />
                    </div>
                    </div>}
                        
                      </GridItem>
                      <GridItem xs={12} sm={12} md={6} lg={6}>
                        <legend>Display Logo</legend>
                        {props.Updating ? 
                          <ImageUpload
                            addButtonProps={{
                              color: "info",
                              round: true,
                            }}
                            changeButtonProps={{
                              color: "info",
                              round: true,
                            }}
                            removeButtonProps={{
                              color: "danger",
                              round: true,
                            }}
                            oldImage={formState.values.displayLogo}
                            name="displayLogo"
                            buttonId="removeLogoImage"
                            handleImageChange={handleImageChange}
                          /> : <div className="fileinput text-center">
                          <div className="thumbnail">
                            <img src={formState.values.displayLogo} alt="..." />
                          </div>
                        </div>}
                        
                      </GridItem>
                    </React.Fragment>
                  )}
                </GridContainer>
                {props.Updating ?
                <>
                <Button
                color="info"
                className={classes.registerButton}
                disabled={formState.isRegistering}
                round
                type="button"
                onClick={handleUpdate}
                >
                  Update
                </Button>
                {formState.isRegistering ? 
                  <CircularProgress disableShrink />
                 : "" } 
                  </>
                  : "" }
                <Button
                  color="danger"
                  className={classes.registerButton}
                  onClick={closeModal}
                  round
                >
                  Close
                </Button>
              </CardBody>
            </Card>
          </GridItem>
        </GridContainer>
      </Animated>
    );
}
