import React, {useState, useEffect} from 'react';
import { makeStyles, withStyles } from '@material-ui/core/styles';
import Stepper from '@material-ui/core/Stepper';
import Step from '@material-ui/core/Step';
import StepLabel from '@material-ui/core/StepLabel';
import StepContent from '@material-ui/core/StepContent';
import StepConnector from '@material-ui/core/StepConnector';
import Card from '@material-ui/core/Card';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemSecondaryAction from '@material-ui/core/ListItemSecondaryAction';
import ListItemText from '@material-ui/core/ListItemText';



const useStyles = makeStyles((theme) => ({
root: {
width: '100%',
},
button: {
marginTop: theme.spacing(1),
marginRight: theme.spacing(1),
}
}));




const QontoConnector = withStyles({
    alternativeLabel: {
    top: 10,
    left: 'calc(-50% + 16px)',
    right: 'calc(50% + 16px)',
    },
    line: {
    borderColor: '#eaeaf0',
    borderTopWidth: 3,
    borderRadius: 1,
    },
})(StepConnector);


export default function VerticalLinearStepper(props) {
const classes = useStyles();
const [activeStep, setActiveStep] = React.useState(0);
const [steps, setSteps] = useState([]);

function generate(element) {
    return [0, 1, 2].map((value) =>
      React.cloneElement(element, {
        key: value,
      }),
    );
  }

useEffect(()=>{
    setSteps(props.data.reverse());
},[])


function getStepContent(stp, ind) {
var step = JSON.parse(stp.Record);
return (
<Card className={classes.root}  variant="outlined" style={{width:600,borderStyle:'dotted',borderColor:'black',padding:5, background:'lightgrey',marginLeft:30*ind}}>
            <div>
                {/* <Typography className={classes.title} color="textSecondary" gutterBottom>
                Document Initialization
                </Typography> */}
                {step.docID ? 
                // 'docHash: "1f9d38ede191d679fa0634a03acf7ea4"
                // docID: "4b41a3475132bd861b30a878e30aa56a-waqas-sample_pdf_27.pdf"
                // event: "review"
                // eventComments: "Review"
                // eventFor: "waqas"
                // eventInitDate: "12/14/2020, 2:25:50 AM"
                // eventStatus: "pending"
                // initedBy: "waqas"
                // workflowID: "5fc744d4dc32e635fce77c96"'
                <div className={classes.demo}>
                <List>
                    <ListItem>
                    <ListItemText
                        primary="Document ID"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.docID}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Block Hash"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.docHash}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Workflow ID"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.workflowID}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Inited By"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.initedBy}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Event For"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.eventFor}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Event Description"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.eventComments}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Event Status"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.eventStatus}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    </List>
                    </div>
                :
                <div className={classes.demo}>
                <List>
                    <ListItem>
                    <ListItemText
                        primary="Workflow Name"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.workflowName}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Block Hash"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.workflowHash}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Workflow Id"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.workflowId}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Organization Name"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.orgName}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Company Name"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.companyName}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Workflow Description"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.workflowDescription}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Review StepsCount"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.reviewStepsCount}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Approve StepsCount"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.approveStepsCount}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Created By"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.createdBy}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Created Date"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.createdDate}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    {step.updatedBy ?
                    <div>
                    <ListItem>
                    <ListItemText
                        primary="Updated By"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.updatedBy}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Updated Date"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.updatedDate}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    </div>
                    :''}
                    {/* <ListItem>
                    <ListItemText
                        primary="Com Name"
                    />
                    <ListItemSecondaryAction>
                        <p>{dateFormat(step.createdBy, "dd/mm/yyyy hh:mm:ss")}</p>
                    </ListItemSecondaryAction>
                    </ListItem> */}
                </List>
            </div>
                }
        </div>
    </Card>)
}


    
const handleNext = (index) => {
setActiveStep(index);
};



return (
<div className={classes.root}>
    <Stepper activeStep={activeStep} orientation="vertical" connector={<QontoConnector />}>
    {steps.map((data, index) => (
        <Step active={true}  key={index} onClick={()=>handleNext(index)}  >
        <StepLabel >{" "}</StepLabel>
        <StepContent>                
            <div>{getStepContent(data, index)}</div>
        </StepContent>
        </Step>
    ))}
    </Stepper>
</div>
);
}