import React, {useState} from "react";
import { Redirect } from "react-router-dom";

// @material-ui/core components
import { makeStyles, TextField, InputAdornment, CircularProgress } from "@material-ui/core";

// @material-ui/icons
import Email from '@material-ui/icons/ScreenLockPortrait';
// import LockOutline from "@material-ui/icons/LockOutline";

// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardBody from "components/Card/CardBody.js";
import CardHeader from "components/Card/CardHeader.js";
import CardFooter from "components/Card/CardFooter.js";

import styles from "assets/jss/material-dashboard-pro-react/views/loginPageStyle.js";
import axios from "axios";
import jwt from "jsonwebtoken";

const useStyles = makeStyles(styles);



export default function LoginSecret(props) {

  const [twofa, setTwofa] = useState("");
  const [loggedIn, setloggedIn] = useState(false);
  const [loading, setLoading] = useState(false);
  const [twofaError, setTwofaError] = useState("");
  const classes = useStyles();

  function handletwofa(event) {
    setTwofa(event.target.value);
  }
  function handleClick(e) {
    e.preventDefault();
    setLoading(true);
    // props.loginOTPsuccess(); 
    let token = localStorage.getItem("cooljwt");
    axios({
      method: "post", //you can set what request you want to be
      url: `${process.env.REACT_APP_LDOCS_API_URL}/lgn/avotp`,
      data: { otp: twofa },
      headers: {
        cooljwt: token,
      },
    }).then((response) => {
      setLoading(false);
        let token = response.headers.cooljwt;
      let decoded = jwt.decode(token);
      console.log(decoded)
      if (decoded.otp) {
          localStorage.setItem("cooljwt", token);
          setTwofaError("success");
          setloggedIn(true);
        } else {
          setTwofaError("error");
        }
       
      })
      .catch((error) => {
        setLoading(false);
        setTwofaError("error");
        console.log(
          typeof error.response != "undefined"
            ? error.response.data
            : error.message
        );
        
      });
  }

  return (
    <div className={classes.container}>
      {loggedIn ? <Redirect to="/admin/dashboard" /> : ""}
      <GridContainer justify="center">
        <GridItem xs={12} sm={6} md={4}>
          <form onSubmit={handleClick}>
            <Card login>
              <CardHeader
                className={`${classes.cardHeader} ${classes.textCenter}`}
                color="info"
              >
                <h4 className={classes.cardTitle}>Secret Key</h4>
              </CardHeader>
              <CardBody>
                <TextField
                  fullWidth={true}
                  error={twofaError === "error"}
                  helperText={twofaError === "error" ? "Invalid OTP" : null}
                  label="Secret key.."
                  id="twofa"
                  name="twofa"
                  onChange={(event) => {
                    handletwofa(event);
                  }}
                  InputProps={{
                    endAdornment: (
                      <InputAdornment position="end">
                        <Email className={classes.inputAdornmentIcon} />
                      </InputAdornment>
                    ),
                  }}
                  type="text"
                  value={twofa || ""}
                />
              </CardBody>
              <CardFooter className={classes.justifyContentCenter}>
                <Button color="info" simple size="lg" block type="submit">
                {loading ? <CircularProgress disableShrink /> : "Enter Secret"}
                </Button>
                
              </CardFooter>
            </Card>
          </form>
        </GridItem>
      </GridContainer>
    </div>
  );
}
