/*eslint-disable*/
import React, { useState, useEffect } from "react";
// @material-ui/core components
import {
MenuItem,
makeStyles,
CircularProgress,
LinearProgress,
TextField,
Switch,
FormControlLabel,
InputAdornment,
Typography
} from "@material-ui/core";


// core components
import MessageIcon from "@material-ui/icons/Message";
// For Chips
import Chip from "@material-ui/core/Chip";
import FaceIcon from "@material-ui/icons/Face";
import DoneIcon from "@material-ui/icons/Done";
import WarningIcon from '@material-ui/icons/Warning';
import defaultAvatar from "assets/img/avatar-2.png";
import CardTravel from "@material-ui/icons/CardTravel";
import Timeline from "./TagsTimeline.js";



import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Avatar from '@material-ui/core/Avatar';


import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import jwt from "jsonwebtoken";
import VisibilityIcon from '@material-ui/icons/Visibility';
import VisibilityOffIcon from '@material-ui/icons/VisibilityOff';
import ViewWorkFlow from "./ViewWorkflow";
import convertUrlToImageData from "./getFileFromUrl";

import { sendNotification, getNotification, sendEventLog } from "actions";
import { useSelector, useDispatch } from "react-redux";
import BlockchainAnimation from "../../../components/BlockchainAnimation/BlockChainAnimation";



// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";

const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);
const Check = require("is-null-empty-or-undefined").Check;




export default function InitWorkflow(props) {
    let Token = localStorage.getItem("cooljwt");
    let decoded = jwt.decode(Token);
    const classes = useStyles();
    const sweetClass = sweetAlertStyle();
    const [isLoading, setIsLoading] = React.useState(false);
    const [isViewWorkFlow, setIsViewWorkflow] = React.useState(false);
    const [isInitWorkFlow, setIsInitWorkFlow] = React.useState(false);
    const [isFileSame, setIsFileSame] = React.useState(true);
    const [alert, setAlert] = React.useState(null);
    const dispatch = useDispatch();

    const warningAlert = (msg) => {
      setAlert(
        <SweetAlert
        warning
        style={{ display: "block", marginTop: "-100px" }}
        title="Warning!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={
            sweetClass.button + " " + sweetClass.warning
        }
        >
         {msg}
        </SweetAlert>
      );
    };
    const successAlert = (msg) => {
      setAlert(
        <SweetAlert
        success
        style={{ display: "block", marginTop: "-100px" }}
        title="Success!"
        onConfirm={() => {hideAlert();props.closeModal()}}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={
            sweetClass.button + " " + sweetClass.success
        }
        >
         {msg}
        </SweetAlert>
      );
    };
    const errorAlert = (msg) => {
    setAlert(
    <SweetAlert
    error
    style={{ display: "block", marginTop: "-100px" }}
    title="Error!"
    onConfirm={() => hideAlert()}
    onCancel={() => hideAlert()}
    confirmBtnCssClass={
        sweetClass.button + " " + sweetClass.danger
    }
    >
    {msg}
    <br />
    For Details Please Contact {process.env.REACT_APP_LDOCS_FOOTER_COPYRIGHT_LEVEL_1}
    </SweetAlert>
    );
    };
    const hideAlert = () => {
        setAlert(null);
    };
    const [formState, setFormState] = React.useState({
      userDetails: null,
      fileAuthDetails: null,
      workFlows:[],
        values: {
            workFlowName:'',
            workflowReviewSteps:[],
            workflowApproveSteps:[],
        },
        errors: {
            workFlowName:''
        },
    });
    const handleChange = (event) => {
        event.persist();
        if (event.target.name == 'workFlowName') {
            setIsLoading(true);
            axios({
                method: "get",
                url: `${process.env.REACT_APP_LDOCS_API_WORKFLOW_URL}/workflow/getWorkflowDetailsByName/${event.target.value}`,
                headers: { cooljwt: Token },
              })
            .then((response)=>{
                setFormState((formState) => ({
                    ...formState,
                    values: {
                    ...formState.values,
                    workflowReviewSteps: response.data.Steps.filter(item=>item.Event == "REVIEWER"),
                    workflowApproveSteps: response.data.Steps.filter(item=>item.Event == "APPROVER")
                    },
                }));
                setIsLoading(false);
            });
        }
        setFormState((formState) => ({
            ...formState,
            values: {
            ...formState.values,
            [event.target.name]: event.target.value,
            },
        }));
    };

    const handleRAChange = (event, sqId) => {
        event.persist();
        if (event.target.name == 'review') {
            var rArray = formState.values.workflowReviewSteps;
            rArray[sqId].SelectedUser=event.target.value.toLowerCase();
            rArray[sqId].Status='pending';
            setFormState((formState) => ({
                ...formState,
                values: {
                ...formState.values,
                workflowReviewSteps: rArray,
                },
            }));
        }
        else if (event.target.name == 'approve') {
            var aArray = formState.values.workflowApproveSteps;
            aArray[sqId].SelectedUser=event.target.value.toLowerCase();
            aArray[sqId].Status='pending';
            setFormState((formState) => ({
                ...formState,
                values: {
                ...formState.values,
                workflowApproveSteps: aArray,
                },
            }));
        }
    }

    
   const getTeamWorkFlows = () => {
    axios({
        method: "get",
        url: `${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/tealist/${decoded.t}`,
        headers: { cooljwt: Token },
      })
        .then((response)=>{
            setFormState((formState) => ({
                ...formState,
                workFlows:response.data.workFlows
            }));
        });
   }

  React.useEffect(() => {
    convertUrlToImageData(`${process.env.REACT_APP_LDOCS_API_URL}/igobgftgsftp/${props.fileData.fileOwner}/${props.fileData.fileId}`).then((res)=>{
      if (res === props.fileData.fileHash ) {
        setIsFileSame(true);
      }else{
        setIsFileSame(false);
        dispatch(sendEventLog(props.fileData, {
          eventTitle:'File is Changed',
          eventDescription:'File is modified (Off_Chain.....)'
        }));
      }
    });
    getTeamWorkFlows();
  },[]);

  const initWorkFlow = () => {
    setIsInitWorkFlow(true);
     let data = {
        fileId:props.fileData.fileId,
        workflowName:formState.values.workFlowName,
        ReviewSteps:formState.values.workflowReviewSteps,
        ApproveSteps:formState.values.workflowApproveSteps,
        createdBy:decoded.loginName,
        status:'pending'
     };
     axios({
      method: "post",
      url: `${process.env.REACT_APP_LDOCS_API_URL}/review/initDocumentWorkflow`,
      data: data,
      headers: { cooljwt: Token },
    })
      .then((response) => {
        //successAlert('WORKFLOW INITIATED');
        props.closeModal()
        props.loadFiles();
    })
  }

    return (
      <GridContainer>
        {alert}
        <GridItem xs={12} sm={12} md={12} >
          <Card>
            <CardHeader color="info" icon>
              <CardIcon color="info">
                <h4 className={classes.cardTitle}>
                  {isInitWorkFlow ? 'MOVING TO BLOCKCHIAN':'INITIATE WORKFLOW'}
                </h4>
              </CardIcon>
            </CardHeader>
            {isInitWorkFlow ?<div style={{width:'100%'}} ><BlockchainAnimation/></div>:
            <CardBody> 
              <GridContainer>
              <GridItem
                      xs={12}
                      sm={12}
                      md={11}
                      lg={11}
                      style={{ marginTop: "10px", marginBottom: "10px" }}
                    >
                      <TextField
                        className={classes.textField}
                        error={formState.errors.organizationName === "error"}
                        fullWidth={true}
                        // helperText={
                        //   formState.errors.organizationName === "error"
                        //     ? "Organization name is required"
                        //     : null
                        // }
                        label="WORKFLOW NAME"
                        name="workFlowName"
                        onChange={(event) => {
                          handleChange(event);
                        }}
                        select
                        value={formState.values.workFlowName || ""}
                      >
                        <MenuItem
                          disabled
                          classes={{ 
                            root: classes.selectMenuItem,
                          }}
                        >
                          CHOOSE WORKFLOW
                        </MenuItem>
                        {formState.workFlows.map((workflow,index)=>{
                            return (
                                <MenuItem key={index} value={workflow}>
                                    {workflow}
                                </MenuItem>
                            )
                        })}
                      </TextField>
                    </GridItem>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={1}
                      lg={1}
                      style={{ marginTop: "10px", marginBottom: "10px" }}
                    >
                    {
                    isLoading
                    ? <CircularProgress /> : 
                    <Avatar onClick={()=>setIsViewWorkflow(!isViewWorkFlow)} style={{background:'#55adc1'}}>
                        {isViewWorkFlow ?<VisibilityIcon />:<VisibilityOffIcon/>}
                    </Avatar>
                    }
                    
                    </GridItem>
    
                    {isViewWorkFlow ?
                    <GridItem
                        xs={12}
                        sm={12}
                        md={12}
                        lg={12}
                        style={{ marginTop: "10px", marginBottom: "10px" }}
                    >
                        <ViewWorkFlow 
                        list={formState.values.workflowReviewSteps.concat(formState.values.workflowApproveSteps)}
                        />
                    </GridItem>:
                    ''}
                    <GridItem
                      xs={12}
                      sm={12}
                      md={6}
                      lg={6}
                      style={{ marginTop: "10px", marginBottom: "10px" }}
                    >
                    {formState.values.workflowReviewSteps.length !== 0 
                    && !isViewWorkFlow
                    ? 
                    <GridContainer>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={12}
                      lg={12}
                      style={{ marginTop: "10px", marginBottom: "10px" }}
                    >
                      <Typography variant="subtitle2">REVIEWER</Typography>
                    </GridItem>
                    {formState.values.workflowReviewSteps.map((reviewStep, index)=>{
                    const isOutSideOrg = reviewStep.IsExternalOrg ? "OUTSIDE ORG" : "INSIDE ORG";
                    return(
                       <GridItem
                            key={index}
                            xs={12}
                            sm={12}
                            md={12}
                            lg={12}
                            style={{ marginTop: "10px", marginBottom: "10px" }}
                            >
                            <TextField
                                className={classes.textField}
                                //error={formState.errors.organizationName === "error"}
                                fullWidth={true}
                                // helperText={
                                //   formState.errors.organizationName === "error"
                                //     ? "Organization name is required"
                                //     : null
                                // }
                                label={`R${index+1} (${reviewStep.Desigination.toUpperCase()}-${isOutSideOrg})`}
                                name="review"
                                onChange={(event) => {
                                handleRAChange(event, index);
                                }}
                                select
                                //value={formState.values.organizationName || ""}
                                value={formState.values.workflowReviewSteps[index].SelectedUser ? 
                                       formState.values.workflowReviewSteps[index].SelectedUser.toUpperCase() : ''
                                }
                            >
                                <MenuItem
                                disabled
                                classes={{ 
                                    root: classes.selectMenuItem,
                                }}
                                >
                                CHOOSE REVIEWER
                                </MenuItem>
                                {
                                reviewStep.Users.map((user,index)=>{
                                    return(
                                        <MenuItem key={index} value={user.toUpperCase()}>
                                            {user.toUpperCase()}
                                        </MenuItem>
                                    )   
                                })
                                }
                            </TextField>
                        </GridItem> 
                        )
                    })}
                    </GridContainer>
                    :''}
                    </GridItem>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={6}
                      lg={6}
                      style={{ marginTop: "10px", marginBottom: "10px" }}
                    >
                    {formState.values.workflowApproveSteps.length !== 0
                    && !isViewWorkFlow
                    ? 
                    <GridContainer>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={12}
                      lg={12}
                      style={{ marginTop: "10px", marginBottom: "10px" }}
                    >
                    <Typography variant="subtitle2" >APPROVERS</Typography>
                    </GridItem>
                    {formState.values.workflowApproveSteps.map((approveStep, index)=>{
                    const isOutSideOrg = approveStep.IsExternalOrg ? "OUTSIDE ORG" : "INSIDE ORG";
                    return(
                       <GridItem
                            key={index}
                            xs={12}
                            sm={12}
                            md={12}
                            lg={12}
                            style={{ marginTop: "10px", marginBottom: "10px" }}
                            >
                            <TextField
                                className={classes.textField}
                                //error={formState.errors.organizationName === "error"}
                                fullWidth={true}
                                // helperText={
                                //   formState.errors.organizationName === "error"
                                //     ? "Organization name is required"
                                //     : null
                                // }
                                label={`A${index+1} (${approveStep.Desigination.toUpperCase()}-${isOutSideOrg})`}
                                name="approve"
                                onChange={(event) => {
                                handleRAChange(event, index);
                                }}
                                select
                                //value={formState.values.organizationName || ""}
                                value={formState.values.workflowApproveSteps[index].SelectedUser ?
                                       formState.values.workflowApproveSteps[index].SelectedUser.toUpperCase():''
                                }
                            >
                                <MenuItem
                                disabled
                                classes={{ 
                                    root: classes.selectMenuItem,
                                }}
                                >
                                CHOOSE APPROVER
                                </MenuItem>
                                {
                                approveStep.Users.map((user,index)=>{
                                    return(
                                        <MenuItem key={index} value={user.toUpperCase()}>
                                            {user.toUpperCase()}
                                        </MenuItem>
                                    )   
                                })
                                }
                            </TextField>
                        </GridItem> 
                        )
                    })}
                    </GridContainer>
                    :''}
                    </GridItem>
                    {!isFileSame ?
                      <GridItem
                      xs={12}
                      sm={12}
                      md={12}
                      lg={12}
                      style={{ marginTop: "10px", marginBottom: "10px" }}
                      >
                     <List style={{width:500}}>
                        <ListItem>
                          <ListItemAvatar>
                                  <Button
                                      justIcon
                                      round
                                      simple
                                      icon={WarningIcon}
                                      color="danger"
                                      className="Edit"
                                    >
                            <WarningIcon />
                          </Button>
                          </ListItemAvatar>
                          <ListItemText primary="File has been modified (Off-Chain)"/>
                        </ListItem>
                      </List>
                      </GridItem>
                      :''}
              </GridContainer>
            <span style={{ float: "right" }}>
                  <React.Fragment>
                    <Button
                      color="info"
                      className={classes.registerButton}
                      round
                      type="button"
                      onClick={initWorkFlow}
                    >
                      {'Init WorkFlow'}
                    </Button>
                    {/* {isSendingFile ? <CircularProgress disableShrink /> : ""} */}
                  </React.Fragment>
                    <Button
                    color="danger"
                    className={classes.registerButton}
                    onClick={props.closeModal}
                    round
                    >
                  Close
                </Button>
              </span> 
            </CardBody>}
          </Card>
        </GridItem>
      </GridContainer>
    );
}
